{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/EdgeFlippers.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class EdgeFlippers < Base\n      # ゲームシステムの識別子\n      ID = 'EdgeFlippers'\n\n      # ゲームシステム名\n      NAME = 'EDGE FLIPPERS'\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = 'えつしふりつはあす'\n\n      # ダイスボットの使い方\n      HELP_MESSAGE = <<~MESSAGETEXT\n        ■ 汎用コマンド\n          xHD+ySD=t,t,t\n          人間ダイスと怪異ダイスをロールして、特定の出目があるか判定します。\n          x: 人間ダイスの数\n          y: 怪異ダイスの数\n          t: 必要な出目（省略化）\n\n        ■ 拮抗判定\n          xHD+ySD=Xi\n          人間ダイスと怪異ダイスをロールして、ゾロ目が必要数あるか判定します。\n          i: 必要なゾロ目の個数\n\n        ■ 全力判定\n          xHFD>=t\n          xSFD>=t\n          x: ダイスの数\n          t: 目標値（省略時20）\n\n        ■ 存在判定\n          EXIST -> 2HD+2SD\n\n        ■ 都市判定\n          xHCD -> xHD=1,2,3,4\n\n        ■ 超常判定\n          nSPD -> nSD=7,8,9,10\n\n        ■ 術式判定\n          TD\n\n        ■ ランダム表\n          BAET：【人間】にも【怪異】にも影響のある後遺症\n          HAET：【人間寄り】の時に影響のある後遺症\n          SAET：【怪異寄り】の時に影響のある後遺症\n      MESSAGETEXT\n\n      def eval_game_system_specific_command(command)\n        roll_hs(command) || roll_alias(command) || roll_fullpower(command) || roll_technical(command) || roll_tables(command, TABLES)\n      end\n\n      private\n\n      class HSCommand\n        class << self\n          def parse(command)\n            m = /^(?:(\\d+)HD(?:\\+(\\d+)SD)?|(\\d+)SD(?:\\+(\\d+)HD)?)(?:=(?:([\\d,]+)|X(\\d+)))?$/.match(command)\n            return nil unless m\n\n            h = m[1]&.to_i || m[4]&.to_i || 0\n            s = m[2]&.to_i || m[3]&.to_i || 0\n            targets = parse_target(m[5])\n            same_value = m[6]&.to_i\n\n            if h == 0 && s == 0\n              return nil\n            end\n\n            return HSCommand.new(h, s, targets, same_value)\n          end\n\n          private\n\n          def parse_target(str)\n            return nil unless str\n\n            str.split(\",\").filter { |s| !s.empty? }.map(&:to_i).sort\n          end\n        end\n\n        def initialize(h, s, targets, same_value)\n          @h = h\n          @s = s\n          @targets = targets\n          @same_value = same_value\n        end\n\n        def roll(randomizer)\n          @hv = randomizer.roll_barabara(@h, 6).sort\n          @sv = randomizer.roll_barabara(@s, 10).sort\n          values = (@hv + @sv).sort\n\n          @is_success = if @targets\n                          subset?(values, @targets)\n                        elsif @same_value\n                          values.group_by(&:itself).any? { |_k, v| v.length >= @same_value }\n                        end\n\n          Result.new.tap do |r|\n            r.text = [expr(), result_values(), result_label].compact.join(\" ＞ \")\n            unless @is_success.nil?\n              r.condition = @is_success\n            end\n          end\n        end\n\n        private\n\n        def subset?(superset, subset)\n          return true if subset.empty?\n\n          i = 0\n          superset.each do |a|\n            b = subset[i]\n            if b == a\n              i += 1\n              if i == subset.length\n                return true\n              end\n            elsif a > b\n              return false\n            end\n          end\n\n          return false\n        end\n\n        def expr\n          \"(\#{expr_body()}\#{expr_cond()})\"\n        end\n\n        def expr_body\n          if @h != 0 && @s != 0\n            \"\#{@h}HD+\#{@s}SD\"\n          elsif @h != 0\n            \"\#{@h}HD\"\n          else\n            \"\#{@s}SD\"\n          end\n        end\n\n        def expr_cond\n          if @targets\n            \"=\#{@targets.join(',')}\"\n          elsif @same_value\n            \"=X\#{@same_value}\"\n          else\n            \"\"\n          end\n        end\n\n        def result_values\n          d6 = !@hv.empty? ? \"D6[\#{@hv.join(',')}]\" : nil\n          d10 = !@sv.empty? ? \"D10[\#{@sv.join(',')}]\" : nil\n          [d6, d10].compact.join(\" \")\n        end\n\n        def result_label\n          case @is_success\n          when true\n            \"成功\"\n          when false\n            \"失敗\"\n          end\n        end\n      end\n\n      def roll_hs(command)\n        cmd = HSCommand.parse(command)\n        return nil unless cmd\n\n        cmd.roll(@randomizer)\n      end\n\n      def parse_target(str)\n        return nil unless str\n\n        str.split(\",\").filter { |s| !s.empty? }.map(&:to_i).sort\n      end\n\n      def subset?(superset, subset)\n        return true if subset.empty?\n\n        i = 0\n        superset.each do |a|\n          b = subset[i]\n          if b == a\n            i += 1\n            if i == subset.length\n              return true\n            end\n          elsif a > b\n            return false\n          end\n        end\n\n        return false\n      end\n\n      def roll_alias(command)\n        case command\n        when \"EXIST\"\n          return roll_hs(\"2HD+2SD\")\n        end\n\n        m = /^(\\d+)(HCD|SPD)$/.match(command)\n        return nil unless m\n\n        n = m[1].to_i\n        case m[2]\n        when \"HCD\"\n          roll_hs(\"\#{n}HD=1,2,3,4\")\n        when \"SPD\"\n          roll_hs(\"\#{n}SD=7,8,9,10\")\n        end\n      end\n\n      def roll_fullpower(command)\n        parser = Command::Parser.new(/[HS]FD/, round_type: @round_type)\n                                .disable_modifier.enable_prefix_number.restrict_cmp_op_to(nil, :>=)\n        parsed = parser.parse(command)\n        return nil unless parsed\n\n        n = parsed.prefix_number\n        side = parsed.command == \"HFD\" ? 6 : 10\n        target = parsed.target_number || 20\n        return nil if n == 0\n\n        dice = @randomizer.roll_barabara(n, side).sort\n        sum = dice.sum()\n        tries = [dice]\n        while sum < target\n          dice = @randomizer.roll_barabara(n, side).sort\n          tries.push(dice)\n          sum += dice.sum()\n        end\n\n        Result.new.tap do |r|\n          r.text = \"(\#{n}\#{parsed.command}>=\#{target})\"\n          tries.each do |ds|\n            r.text += \" ＞ \#{ds.sum}[\#{ds.join(',')}]\"\n          end\n\n          is_success = tries.length < 5\n          r.text += \" ＞ \#{sum}(\#{tries.length}回)\"\n          r.text += is_success ? \" ＞ 成功\" : \" ＞ 失敗\"\n          r.condition = is_success\n        end\n      end\n\n      def roll_technical(command)\n        return nil unless command == \"TD\"\n\n        value = @randomizer.roll_once(10)\n        is_success = value <= 2\n        Result.new.tap do |r|\n          r.text = \"(TD) ＞ \#{value} ＞ \#{is_success ? '成功' : '失敗'}\"\n          r.condition = is_success\n        end\n      end\n\n      TABLES = {\n        \"BAET\" => DiceTable::Table.new(\n          \"【人間】にも【怪異】にも影響のある後遺症\",\n          \"1D12\",\n          [\n            \"鏡に映らない：鏡や水面に姿が映らなくなる。他者から見えなくなるわけではない\",\n            \"部分的に透明：身体のどこかが透明になる\",\n            \"部分的欠落：身体のどこかが消えて触ることもできなくなる。生命維持に影響はない\",\n            \"角が生える：角が生えてくる。元から角がある場合はさらに追加\",\n            \"しっぽ：動物のしっぽが生える\",\n            \"けもみみ：動物の耳が頭に生える\",\n            \"影がなくなる：自分の影がなくなってしまう\",\n            \"涙が止まらない：ずっと涙が流れ続けて止まらなくなる\",\n            \"視界の端に何かいる：常に視界の端に何かがいて、踊っている\",\n            \"耳鳴り：ずっと耳鳴りがやまない。たまに幻聴がする\",\n            \"美しい幻聴：時々他人の声が現実離れした美しい声に変わって聞こえる\",\n            \"皮膚の下のうごめき：皮膚の下でずっと何かが蠢いているように感じられる\",\n          ]\n        ),\n        \"HAET\" => DiceTable::Table.new(\n          \"【人間寄り】の時に影響のある後遺症\",\n          \"1D6\",\n          [\n            \"幻肢の感覚：存在しない追加の腕や翼の感覚がある\",\n            \"声変わり：普段とは違う声になってしまう\",\n            \"怪異の片鱗：【怪異寄り】のときの容姿の一部が【人間寄り】の時にも出てしまう\",\n            \"幻覚：時折やけに生々しい幻覚が見えるようになる\",\n            \"恐怖：あらゆるものが怖く見える\",\n            \"怪異言語：【人間】の領域には存在しない謎の言語が理解できる\",\n          ]\n        ),\n        \"SAET\" => DiceTable::Table.new(\n          \"【怪異寄り】の時に影響のある後遺症\",\n          \"1D6\",\n          [\n            \"吸精体質：他者に触れると生命力を吸収してしまう。特に仲の良い相手だとより強くなる\",\n            \"威圧する視線：あなたの視線は周囲に強烈な威圧感を与えてしまう\",\n            \"キメラ：あなたの容姿の一部が、他の【越境者】の【怪異寄り】のときの容姿のものと同じになる\",\n            \"異なる怪異：あなた本来の【怪異】の姿とは違う姿に変化してしまう\",\n            \"ポルターガイスト：周囲でラップ音や部品の浮遊といった怪現象が多発する\",\n            \"人間そのもの：【怪異寄り】のときでも人間そのものの容姿になってしまう\",\n          ]\n        ),\n      }.freeze\n\n      register_prefix('\\d+HD', '\\d+SD', '\\d+HCD', '\\d+SPD', '\\d+HFD', '\\dSFD', 'EXIST', 'TD', TABLES.keys)\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<module:GameSystem>", "<class:EdgeFlippers>", "eval_game_system_specific_command", "command", "$ret_or_1", "$ret_or_2", "$ret_or_3", "$ret_or_4", "self", "roll_hs", "roll_alias", "roll_fullpower", "roll_technical", "roll_tables", "TABLES", "private", "<class:HSCommand>", "parse", "m", "match", "h", "[]", "1", "4", "0", "s", "2", "3", "targets", "parse_target", "5", "same_value", "6", "HSCommand", "new", "str", "map", "filter", "split", "block in parse_target", "block (2 levels) in parse_target", "empty?", "!", "to_proc", "sort", "initialize", "@h", "@s", "@targets", "@same_value", "roll", "randomizer", "@hv", "roll_barabara", "@sv", "10", "values", "+", "@is_success", "subset?", "any?", "group_by", "block in roll", "_k", "v", "block (2 levels) in roll", ">=", "length", "tap", "Result", "r", "text=", "expr", "result_values", "result_label", "compact", "join", "nil?", "condition=", "superset", "subset", "i", "each", "block in subset?", "a", "block (2 levels) in subset?", "b", ">", "expr_body", "expr_cond", "d6", "d10", "cmd", "@randomizer", "n", "to_i", "parser", "Command::Parser", "Command", "@round_type", "disable_modifier", "enable_prefix_number", "restrict_cmp_op_to", "parsed", "prefix_number", "side", "target", "target_number", "20", "dice", "sum", "tries", "<", "push", "block in roll_fullpower", "block (2 levels) in roll_fullpower", "ds", "block (3 levels) in roll_fullpower", "text", "is_success", "value", "roll_once", "<=", "block in roll_technical", "block (2 levels) in roll_technical", "DiceTable::Table", "DiceTable", "freeze", "register_prefix", "keys", "Base"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QAEE,8BAAKA,cAAL;QAGA,gCAAOA,eAAP;QAGA,oCAAWA,WAAX;QAGA,wCACNA,YADqB,GAErBA,mBAFqB,GAGrBA,uCAHqB,GAIrBA,gBAJqB,GAKrBA,gBALqB,GAMrBA,mBANqB,GAOrBA,IAPqB,GAQrBA,UARqB,GASrBA,gBATqB,GAUrBA,wCAVqB,GAWrBA,kBAXqB,GAYrBA,IAZqB,GAarBA,UAbqB,GAcrBA,aAdqB,GAerBA,aAfqB,GAgBrBA,cAhBqB,GAiBrBA,mBAjBqB,GAkBrBA,IAlBqB,GAmBrBA,UAnBqB,GAoBrBA,sBApBqB,GAqBrBA,IArBqB,GAsBrBA,UAtBqB,GAuBrBA,yBAvBqB,GAwBrBA,IAxBqB,GAyBrBA,UAzBqB,GA0BrBA,0BA1BqB,GA2BrBA,IA3BqB,GA4BrBA,UA5BqB,GA6BrBA,QA7BqB,GA8BrBA,IA9BqB,GA+BrBA,WA/BqB,GAgCrBA,+BAhCqB,GAiCrBA,4BAjCqB,GAkCrBA,4BAlCM;;AAqCAC,QAAAA,iDAAAA,6CAAsCC,OAAtCD;AAAAA,UAAAA;;UACE,IAAA,QAAAE,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAAC,IAAAC,SAAAA,CAAQN,OAARM,CAAAF,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAoBC,IAAAE,YAAAA,CAAWP,OAAXO,CAApB,CAAA,CAAAJ,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAA2CE,IAAAG,gBAAAA,CAAeR,OAAfQ,CAA3C,CAAA,CAAAN,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAsEG,IAAAI,gBAAAA,CAAeT,OAAfS,CAAtE,CAAA,CAAAR,CAAA,CAAA;YAAAF,OAAA;UAAA;YAAiGA,OAAAM,IAAAK,aAAAA,CAAYV,OAAZ,EAAqBW,YAArBD;UAAjG;QADFX,CAAAA;QAIAM,IAAAO,SAAAA,CAAAA;QAEAC;QAAAA;;UAAAA;;AAAAA;;UACE;YAAA;;;;AACEC,YAAAA,qBAAAA,iBAAUd,OAAVc;AAAAA,cAAAA;;;cACEC,IAAI,4EAA4EC,OAAAA,CAAOhB,OAAPgB;cAChF,KAAA,QAAkBD,CAAlB,CAAA;gBAAA,OAAO;cAAP;cAEAE,IAAI,CAAA,QAAAhB,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAA,CAAA,KAAAa,CAACG,OAAAA,CAACC,CAADD,CAAD,qCAAA,EAAA,MAAA,CAAA,CAAA,CAAAhB,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAc,CAAA,KAAAa,CAACG,OAAAA,CAACE,CAADF,CAAD,qCAAA,EAAA,MAAA,CAAA,CAAA,CAAd,CAAA,CAAAjB,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAA4BoB,CAA5B,CAAA;cACJC,IAAI,CAAA,QAAArB,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAA,CAAA,KAAAa,CAACG,OAAAA,CAACK,CAADL,CAAD,qCAAA,EAAA,MAAA,CAAA,CAAA,CAAAhB,CAAA,CAAA,GAAA,CAAA,SAAA,IAA